1617 static void narrowToSingleScalarRecipes(VPlan &Plan) {
1618   if (Plan.hasScalarVFOnly())
1619     return;
1620 
1621   // Try to narrow wide and replicating recipes to single scalar recipes,
1622   // based on VPlan analysis. Only process blocks in the loop region for now,
1623   // without traversing into nested regions, as recipes in replicate regions
1624   // cannot be converted yet.
1625   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
1626            vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()))) {
1627     for (VPRecipeBase &R : make_early_inc_range(reverse(*VPBB))) {
1628       if (!isa<VPWidenRecipe, VPWidenGEPRecipe, VPReplicateRecipe,
1629                VPWidenStoreRecipe>(&R))
1630         continue;
1631       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
1632       if (RepR && (RepR->isSingleScalar() || RepR->isPredicated()))
1633         continue;
1634 
1635       // Convert an unmasked scatter with an uniform address into
1636       // extract-last-lane + scalar store.
1637       // TODO: Add a profitability check comparing the cost of a scatter vs.
1638       // extract + scalar store.
1639       auto *WidenStoreR = dyn_cast<VPWidenStoreRecipe>(&R);
1640       if (WidenStoreR && vputils::isSingleScalar(WidenStoreR->getAddr()) &&
1641           !WidenStoreR->isConsecutive()) {
1642         assert(!WidenStoreR->isReverse() &&
1643                "Not consecutive memory recipes shouldn't be reversed");
1644         VPValue *Mask = WidenStoreR->getMask();
1645 
1646         // Only convert the scatter to a scalar store if it is unmasked.
1647         // TODO: Support converting scatter masked by the header mask to scalar
1648         // store.
1649         if (Mask)
1650           continue;
1651 
1652         auto *Extract = new VPInstruction(VPInstruction::ExtractLastLane,
1653                                           {WidenStoreR->getOperand(1)});
1654         Extract->insertBefore(WidenStoreR);
1655 
1656         // TODO: Sink the scalar store recipe to middle block if possible.
1657         auto *ScalarStore = new VPReplicateRecipe(
1658             &WidenStoreR->getIngredient(), {Extract, WidenStoreR->getAddr()},
1659             true /*IsSingleScalar*/, nullptr /*Mask*/, {},
1660             *WidenStoreR /*Metadata*/);
1661         ScalarStore->insertBefore(WidenStoreR);
1662         WidenStoreR->eraseFromParent();
1663         continue;
1664       }
1665 
1666       auto *RepOrWidenR = dyn_cast<VPRecipeWithIRFlags>(&R);
1667       if (RepR && isa<StoreInst>(RepR->getUnderlyingInstr()) &&
1668           vputils::isSingleScalar(RepR->getOperand(1))) {
1669         auto *Clone = new VPReplicateRecipe(
1670             RepOrWidenR->getUnderlyingInstr(), RepOrWidenR->operands(),
1671             true /*IsSingleScalar*/, nullptr /*Mask*/, *RepR /*Flags*/,
1672             *RepR /*Metadata*/, RepR->getDebugLoc());
1673         Clone->insertBefore(RepOrWidenR);
1674         VPBuilder Builder(Clone);
1675         VPValue *ExtractOp = Clone->getOperand(0);
1676         if (vputils::isUniformAcrossVFsAndUFs(RepR->getOperand(1)))
1677           ExtractOp =
1678               Builder.createNaryOp(VPInstruction::ExtractLastPart, ExtractOp);
1679         ExtractOp =
1680             Builder.createNaryOp(VPInstruction::ExtractLastLane, ExtractOp);
1681         Clone->setOperand(0, ExtractOp);
