1730 /// Try to see if all of \p Blend's masks share a common value logically and'ed
1731 /// and remove it from the masks.
1732 static void removeCommonBlendMask(VPBlendRecipe *Blend) {
1733   if (Blend->isNormalized())
1734     return;
1735   VPValue *CommonEdgeMask;
1736   if (!match(Blend->getMask(0),
1737              m_LogicalAnd(m_VPValue(CommonEdgeMask), m_VPValue())))
1738     return;
1739   for (unsigned I = 0; I < Blend->getNumIncomingValues(); I++)
1740     if (!match(Blend->getMask(I),
1741                m_LogicalAnd(m_Specific(CommonEdgeMask), m_VPValue())))
1742       return;
1743   for (unsigned I = 0; I < Blend->getNumIncomingValues(); I++)
1744     Blend->setMask(I, Blend->getMask(I)->getDefiningRecipe()->getOperand(1));
1745 }
