1747 /// Normalize and simplify VPBlendRecipes. Should be run after simplifyRecipes
1748 /// to make sure the masks are simplified.
1749 static void simplifyBlends(VPlan &Plan) {
1750   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
1751            vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()))) {
1752     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
1753       auto *Blend = dyn_cast<VPBlendRecipe>(&R);
1754       if (!Blend)
1755         continue;
1756 
1757       removeCommonBlendMask(Blend);
1758 
1759       // Try to remove redundant blend recipes.
1760       SmallPtrSet<VPValue *, 4> UniqueValues;
1761       if (Blend->isNormalized() || !match(Blend->getMask(0), m_False()))
1762         UniqueValues.insert(Blend->getIncomingValue(0));
1763       for (unsigned I = 1; I != Blend->getNumIncomingValues(); ++I)
1764         if (!match(Blend->getMask(I), m_False()))
1765           UniqueValues.insert(Blend->getIncomingValue(I));
1766 
1767       if (UniqueValues.size() == 1) {
1768         Blend->replaceAllUsesWith(*UniqueValues.begin());
1769         Blend->eraseFromParent();
1770         continue;
1771       }
1772 
1773       if (Blend->isNormalized())
1774         continue;
1775 
1776       // Normalize the blend so its first incoming value is used as the initial
1777       // value with the others blended into it.
1778 
1779       unsigned StartIndex = 0;
1780       for (unsigned I = 0; I != Blend->getNumIncomingValues(); ++I) {
1781         // If a value's mask is used only by the blend then is can be deadcoded.
1782         // TODO: Find the most expensive mask that can be deadcoded, or a mask
1783         // that's used by multiple blends where it can be removed from them all.
1784         VPValue *Mask = Blend->getMask(I);
1785         if (Mask->getNumUsers() == 1 && !match(Mask, m_False())) {
1786           StartIndex = I;
1787           break;
1788         }
1789       }
1790 
1791       SmallVector<VPValue *, 4> OperandsWithMask;
1792       OperandsWithMask.push_back(Blend->getIncomingValue(StartIndex));
1793 
1794       for (unsigned I = 0; I != Blend->getNumIncomingValues(); ++I) {
1795         if (I == StartIndex)
1796           continue;
1797         OperandsWithMask.push_back(Blend->getIncomingValue(I));
1798         OperandsWithMask.push_back(Blend->getMask(I));
1799       }
1800 
1801       auto *NewBlend =
1802           new VPBlendRecipe(cast_or_null<PHINode>(Blend->getUnderlyingValue()),
1803                             OperandsWithMask, *Blend, Blend->getDebugLoc());
1804       NewBlend->insertBefore(&R);
1805 
1806       VPValue *DeadMask = Blend->getMask(StartIndex);
1807       Blend->replaceAllUsesWith(NewBlend);
1808       Blend->eraseFromParent();
1809       recursivelyDeleteDeadRecipes(DeadMask);
1810 
1811       /// Simplify BLEND %a, %b, Not(%mask) -> BLEND %b, %a, %mask.
1812       VPValue *NewMask;
1813       if (NewBlend->getNumOperands() == 3 &&
1814           match(NewBlend->getMask(1), m_Not(m_VPValue(NewMask)))) {
1815         VPValue *Inc0 = NewBlend->getOperand(0);
1816         VPValue *Inc1 = NewBlend->getOperand(1);
1817         VPValue *OldMask = NewBlend->getOperand(2);
1818         NewBlend->setOperand(0, Inc1);
1819         NewBlend->setOperand(1, Inc0);
1820         NewBlend->setOperand(2, NewMask);
1821         if (OldMask->getNumUsers() == 0)
1822           cast<VPInstruction>(OldMask)->eraseFromParent();
1823       }
1824     }
1825   }
