1828 /// Optimize the width of vector induction variables in \p Plan based on a known
1829 /// constant Trip Count, \p BestVF and \p BestUF.
1830 static bool optimizeVectorInductionWidthForTCAndVFUF(VPlan &Plan,
1831                                                      ElementCount BestVF,
1832                                                      unsigned BestUF) {
1833   // Only proceed if we have not completely removed the vector region.
1834   if (!Plan.getVectorLoopRegion())
1835     return false;
1836 
1837   const APInt *TC;
1838   if (!BestVF.isFixed() || !match(Plan.getTripCount(), m_APInt(TC)))
1839     return false;
1840 
1841   // Calculate the minimum power-of-2 bit width that can fit the known TC, VF
1842   // and UF. Returns at least 8.
1843   auto ComputeBitWidth = [](APInt TC, uint64_t Align) {
1844     APInt AlignedTC =
1845         Align * APIntOps::RoundingUDiv(TC, APInt(TC.getBitWidth(), Align),
1846                                        APInt::Rounding::UP);
1847     APInt MaxVal = AlignedTC - 1;
1848     return std::max<unsigned>(PowerOf2Ceil(MaxVal.getActiveBits()), 8);
