2543 /// Move loop-invariant recipes out of the vector loop region in \p Plan.
2544 static void licm(VPlan &Plan) {
2545   VPBasicBlock *Preheader = Plan.getVectorPreheader();
2546 
2547   // Hoist any loop invariant recipes from the vector loop region to the
2548   // preheader. Preform a shallow traversal of the vector loop region, to
2549   // exclude recipes in replicate regions. Since the top-level blocks in the
2550   // vector loop region are guaranteed to execute if the vector pre-header is,
2551   // we don't need to check speculation safety.
2552   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
2553   assert(Preheader->getSingleSuccessor() == LoopRegion &&
2554          "Expected vector prehader's successor to be the vector loop region");
2555   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2556            vp_depth_first_shallow(LoopRegion->getEntry()))) {
2557     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
2558       if (cannotHoistOrSinkRecipe(R))
2559         continue;
2560       if (any_of(R.operands(), [](VPValue *Op) {
2561             return !Op->isDefinedOutsideLoopRegions();
2562           }))
2563         continue;
2564       R.moveBefore(*Preheader, Preheader->end());
2565     }
2566   }
2567 
2568 #ifndef NDEBUG
2569   VPDominatorTree VPDT(Plan);
2570 #endif
2571   // Sink recipes with no users inside the vector loop region if all users are
2572   // in the same exit block of the region.
2573   // TODO: Extend to sink recipes from inner loops.
2574   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2575            vp_post_order_shallow(LoopRegion->getEntry()))) {
2576     for (VPRecipeBase &R : make_early_inc_range(reverse(*VPBB))) {
2577       if (cannotHoistOrSinkRecipe(R))
2578         continue;
2579 
2580       // TODO: Support sinking VPReplicateRecipe after ensuring replicateByVF
2581       // handles sunk recipes correctly.
2582       if (isa<VPReplicateRecipe>(&R))
2583         continue;
2584 
2585       // TODO: Use R.definedValues() instead of casting to VPSingleDefRecipe to
2586       // support recipes with multiple defined values (e.g., interleaved loads).
2587       auto *Def = cast<VPSingleDefRecipe>(&R);
2588       // Skip recipes without users as we cannot determine a sink block.
2589       // TODO: Clone sinkable recipes without users to all exit blocks to reduce
2590       // their execution frequency.
2591       if (Def->getNumUsers() == 0)
2592         continue;
2593 
2594       VPBasicBlock *SinkBB = nullptr;
2595       // Cannot sink the recipe if any user
2596       //  * is defined in any loop region, or
2597       //  * is a phi, or
2598       //  * multiple users in different blocks.
2599       if (any_of(Def->users(), [&SinkBB](VPUser *U) {
2600             auto *UserR = cast<VPRecipeBase>(U);
2601             VPBasicBlock *Parent = UserR->getParent();
2602             // TODO: If the user is a PHI node, we should check the block of
2603             // incoming value. Support PHI node users if needed.
2604             if (UserR->isPhi() || Parent->getEnclosingLoopRegion())
2605               return true;
2606             // TODO: Support sinking when users are in multiple blocks.
2607             if (SinkBB && SinkBB != Parent)
2608               return true;
2609             SinkBB = Parent;
2610             return false;
2611           }))
2612         continue;
2613 
2614       // Only sink to dedicated exit blocks of the loop region.
2615       if (SinkBB->getSinglePredecessor() != LoopRegion)
2616         continue;
2617 
2618       // TODO: This will need to be a check instead of a assert after
2619       // conditional branches in vectorized loops are supported.
2620       assert(VPDT.properlyDominates(VPBB, SinkBB) &&
2621              "Defining block must dominate sink block");
2622       // TODO: Clone the recipe if users are on multiple exit paths, instead of
2623       // just moving.
2624       Def->moveBefore(*SinkBB, SinkBB->getFirstNonPhi());
2625     }
2626   }
