2629 void VPlanTransforms::truncateToMinimalBitwidths(
2630     VPlan &Plan, const MapVector<Instruction *, uint64_t> &MinBWs) {
2631   if (Plan.hasScalarVFOnly())
2632     return;
2633   // Keep track of created truncates, so they can be re-used. Note that we
2634   // cannot use RAUW after creating a new truncate, as this would could make
2635   // other uses have different types for their operands, making them invalidly
2636   // typed.
2637   DenseMap<VPValue *, VPWidenCastRecipe *> ProcessedTruncs;
2638   VPTypeAnalysis TypeInfo(Plan);
2639   VPBasicBlock *PH = Plan.getVectorPreheader();
2640   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2641            vp_depth_first_deep(Plan.getVectorLoopRegion()))) {
2642     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
2643       if (!isa<VPWidenRecipe, VPWidenCastRecipe, VPReplicateRecipe,
2644                VPWidenLoadRecipe, VPWidenIntrinsicRecipe>(&R))
2645         continue;
2646 
2647       VPValue *ResultVPV = R.getVPSingleValue();
2648       auto *UI = cast_or_null<Instruction>(ResultVPV->getUnderlyingValue());
2649       unsigned NewResSizeInBits = MinBWs.lookup(UI);
2650       if (!NewResSizeInBits)
2651         continue;
2652 
2653       // If the value wasn't vectorized, we must maintain the original scalar
2654       // type. Skip those here, after incrementing NumProcessedRecipes. Also
2655       // skip casts which do not need to be handled explicitly here, as
2656       // redundant casts will be removed during recipe simplification.
2657       if (isa<VPReplicateRecipe, VPWidenCastRecipe>(&R))
2658         continue;
2659 
2660       Type *OldResTy = TypeInfo.inferScalarType(ResultVPV);
2661       unsigned OldResSizeInBits = OldResTy->getScalarSizeInBits();
2662       assert(OldResTy->isIntegerTy() && "only integer types supported");
2663       (void)OldResSizeInBits;
2664 
2665       auto *NewResTy = IntegerType::get(Plan.getContext(), NewResSizeInBits);
2666 
2667       // Any wrapping introduced by shrinking this operation shouldn't be
2668       // considered undefined behavior. So, we can't unconditionally copy
2669       // arithmetic wrapping flags to VPW.
2670       if (auto *VPW = dyn_cast<VPRecipeWithIRFlags>(&R))
2671         VPW->dropPoisonGeneratingFlags();
2672 
2673       if (OldResSizeInBits != NewResSizeInBits &&
2674           !match(&R, m_ICmp(m_VPValue(), m_VPValue()))) {
2675         // Extend result to original width.
2676         auto *Ext = new VPWidenCastRecipe(
2677             Instruction::ZExt, ResultVPV, OldResTy, nullptr,
2678             VPIRFlags::getDefaultFlags(Instruction::ZExt));
2679         Ext->insertAfter(&R);
2680         ResultVPV->replaceAllUsesWith(Ext);
2681         Ext->setOperand(0, ResultVPV);
2682         assert(OldResSizeInBits > NewResSizeInBits && "Nothing to shrink?");
2683       } else {
2684         assert(match(&R, m_ICmp(m_VPValue(), m_VPValue())) &&
2685                "Only ICmps should not need extending the result.");
2686       }
2687 
2688       assert(!isa<VPWidenStoreRecipe>(&R) && "stores cannot be narrowed");
2689       if (isa<VPWidenLoadRecipe, VPWidenIntrinsicRecipe>(&R))
2690         continue;
2691 
2692       // Shrink operands by introducing truncates as needed.
2693       unsigned StartIdx =
2694           match(&R, m_Select(m_VPValue(), m_VPValue(), m_VPValue())) ? 1 : 0;
2695       for (unsigned Idx = StartIdx; Idx != R.getNumOperands(); ++Idx) {
2696         auto *Op = R.getOperand(Idx);
2697         unsigned OpSizeInBits =
2698             TypeInfo.inferScalarType(Op)->getScalarSizeInBits();
2699         if (OpSizeInBits == NewResSizeInBits)
2700           continue;
2701         assert(OpSizeInBits > NewResSizeInBits && "nothing to truncate");
2702         auto [ProcessedIter, IterIsEmpty] = ProcessedTruncs.try_emplace(Op);
2703         if (!IterIsEmpty) {
2704           R.setOperand(Idx, ProcessedIter->second);
2705           continue;
2706         }
2707 
2708         VPBuilder Builder;
2709         if (isa<VPIRValue>(Op))
2710           Builder.setInsertPoint(PH);
2711         else
2712           Builder.setInsertPoint(&R);
2713         VPWidenCastRecipe *NewOp =
2714             Builder.createWidenCast(Instruction::Trunc, Op, NewResTy);
2715         ProcessedIter->second = NewOp;
2716         R.setOperand(Idx, NewOp);
2717       }
2718 
2719     }
2720   }
2721 }
