2723 void VPlanTransforms::removeBranchOnConst(VPlan &Plan) {
2724   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2725            vp_depth_first_shallow(Plan.getEntry()))) {
2726     VPValue *Cond;
2727     // Skip blocks that are not terminated by BranchOnCond.
2728     if (VPBB->empty() || !match(&VPBB->back(), m_BranchOnCond(m_VPValue(Cond))))
2729       continue;
2730 
2731     assert(VPBB->getNumSuccessors() == 2 &&
2732            "Two successors expected for BranchOnCond");
2733     unsigned RemovedIdx;
2734     if (match(Cond, m_True()))
2735       RemovedIdx = 1;
2736     else if (match(Cond, m_False()))
2737       RemovedIdx = 0;
2738     else
2739       continue;
2740 
2741     VPBasicBlock *RemovedSucc =
2742         cast<VPBasicBlock>(VPBB->getSuccessors()[RemovedIdx]);
2743     assert(count(RemovedSucc->getPredecessors(), VPBB) == 1 &&
2744            "There must be a single edge between VPBB and its successor");
2745     // Values coming from VPBB into phi recipes of RemoveSucc are removed from
2746     // these recipes.
2747     for (VPRecipeBase &R : RemovedSucc->phis())
2748       cast<VPPhiAccessors>(&R)->removeIncomingValueFor(VPBB);
2749 
2750     // Disconnect blocks and remove the terminator. RemovedSucc will be deleted
2751     // automatically on VPlan destruction if it becomes unreachable.
2752     VPBlockUtils::disconnectBlocks(VPBB, RemovedSucc);
2753     VPBB->back().eraseFromParent();
2754   }
2755 }
