1226     if (TruncTy == ATy) {
1227       Def->replaceAllUsesWith(A);
1228     } else {
1229       // Don't replace a scalarizing recipe with a widened cast.
1230       if (isa<VPReplicateRecipe>(Def))
1231         return;
