1233 
1234         unsigned ExtOpcode = match(Def->getOperand(0), m_SExt(m_VPValue()))
1235                                  ? Instruction::SExt
1236                                  : Instruction::ZExt;
1237         auto *Ext = Builder.createWidenCast(Instruction::CastOps(ExtOpcode), A,
1238                                             TruncTy);
