1606 void VPlanTransforms::simplifyRecipes(VPlan &Plan) {
1607   ReversePostOrderTraversal<VPBlockDeepTraversalWrapper<VPBlockBase *>> RPOT(
1608       Plan.getEntry());
1609   VPTypeAnalysis TypeInfo(Plan);
1610   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(RPOT)) {
1611     for (VPRecipeBase &R : make_early_inc_range(*VPBB))
1612       if (auto *Def = dyn_cast<VPSingleDefRecipe>(&R))
1613         simplifyRecipe(Def, TypeInfo);
1614   }
